class PlanStep(BaseModel):
    action: str
    target: str
    target_from: str
    secondary_target: str
    secondary_from: str
    content: str
    content_from: str
    instruction: str
    input_names: list[str]
    output_name: str


class Plan(BaseModel):
    steps: list[PlanStep]


class AITextResult(BaseModel):
    value: str


class AIStringListResult(BaseModel):
    values: list[str]


class UserEmailPair(BaseModel):
    user: str
    user_email: EmailStr


class AIUserEmailPairsResult(BaseModel):
    pairs: list[UserEmailPair]


class DirectMessageDraft(BaseModel):
    recipient: str
    body: str


class AIDirectMessagesResult(BaseModel):
    messages: list[DirectMessageDraft]


class ChannelMessageDraft(BaseModel):
    channel: str
    body: str


class AIChannelMessagesResult(BaseModel):
    messages: list[ChannelMessageDraft]


class UserChannelPair(BaseModel):
    user: str
    channel: str


class AIUserChannelPairsResult(BaseModel):
    pairs: list[UserChannelPair]


class UrlContentPair(BaseModel):
    url: str
    content: str


class AIUrlContentPairsResult(BaseModel):
    pairs: list[UrlContentPair]


todo_url = "www.company-todo-list.com/bob"
todo_page = get_webpage(todo_url)

